import { DEFAULT_PREFERENCES, SITE_LABELS } from '../lib/constants';
import { sendRuntimeMessage } from '../lib/runtime';
import type { AppSnapshot, Preferences, ResetRuleKind, SiteId } from '../types';

const saveState = document.querySelector<HTMLElement>('#save-state')!;
const siteSettings = document.querySelector<HTMLElement>('#site-settings')!;

const siteOrder: SiteId[] = ['chatgpt', 'claude', 'gemini', 'perplexity', 'grok'];

function setStatus(message: string): void {
  saveState.textContent = message;
}

function fillSelect(element: HTMLSelectElement, options: Array<{ value: string; label: string }>, value: string): void {
  element.innerHTML = options.map((option) => `<option value="${option.value}">${option.label}</option>`).join('');
  element.value = value;
}

function renderSiteCard(site: SiteId, preferences: Preferences): string {
  const settings = preferences.sites[site];
  return `
    <article class="site-card" data-site="${site}">
      <div>
        <h3>${SITE_LABELS[site]}</h3>
        <p>${settings.resetRule.description ?? 'Configure how Yor should estimate this site.'}</p>
      </div>
      <label class="field inline"><input data-key="enabled" type="checkbox" ${settings.enabled ? 'checked' : ''}/> <span>Enable tracking</span></label>
      <label class="field"><span>Reset rule</span>
        <select data-key="resetKind">
          ${['rolling', 'hourly', 'daily', 'weekly', 'custom', 'unknown'].map((value) => `<option value="${value}" ${settings.resetRule.kind === value ? 'selected' : ''}>${value}</option>`).join('')}
        </select>
      </label>
      <label class="field"><span>Interval minutes</span><input data-key="intervalMinutes" type="number" min="1" value="${settings.resetRule.intervalMinutes ?? ''}" /></label>
      <label class="field"><span>Anchor time</span><input data-key="anchorLocalTime" type="time" value="${settings.resetRule.anchorLocalTime ?? '00:00'}" /></label>
      <label class="field"><span>Day of week (0-6)</span><input data-key="dayOfWeek" type="number" min="0" max="6" value="${settings.resetRule.dayOfWeek ?? 1}" /></label>
      <label class="field"><span>Window token budget</span><input data-key="tokenBudget" type="number" min="0" step="100" value="${settings.tokenBudget ?? ''}" /></label>
      <label class="field"><span>Context window</span><input data-key="contextWindow" type="number" min="0" step="1000" value="${settings.contextWindow ?? ''}" /></label>
      <label class="field"><span>Quota tier label</span><input data-key="quotaTierLabel" type="text" value="${settings.quotaTierLabel ?? ''}" /></label>
      <label class="field"><span>Input cost / 1K</span><input data-key="costInputPer1k" type="number" min="0" step="0.0001" value="${settings.costInputPer1k ?? ''}" /></label>
      <label class="field"><span>Output cost / 1K</span><input data-key="costOutputPer1k" type="number" min="0" step="0.0001" value="${settings.costOutputPer1k ?? ''}" /></label>
    </article>
  `;
}

function readNumber(value: string): number | undefined {
  if (!value.trim()) return undefined;
  const number = Number(value);
  return Number.isFinite(number) ? number : undefined;
}

function collectPreferences(snapshot: AppSnapshot): Preferences {
  const next: Preferences = structuredClone(snapshot.state.preferences);
  next.theme = (document.querySelector<HTMLSelectElement>('#theme')!.value as Preferences['theme']);
  next.privacyMode = (document.querySelector<HTMLSelectElement>('#privacy-mode')!.value as Preferences['privacyMode']);
  next.alerts.badgeMode = (document.querySelector<HTMLSelectElement>('#badge-mode')!.value as Preferences['alerts']['badgeMode']);
  next.showOverlay = document.querySelector<HTMLInputElement>('#show-overlay')!.checked;
  next.compactMode = document.querySelector<HTMLInputElement>('#compact-mode')!.checked;
  next.alerts.desktopNotifications = document.querySelector<HTMLInputElement>('#desktop-notifications')!.checked;
  next.alerts.quotaWarningPercent = Number(document.querySelector<HTMLInputElement>('#quota-warning-percent')!.value);
  next.alerts.largePromptTokens = Number(document.querySelector<HTMLInputElement>('#large-prompt-tokens')!.value);
  next.alerts.anomalyMultiplier = Number(document.querySelector<HTMLInputElement>('#anomaly-multiplier')!.value);

  for (const site of siteOrder) {
    const card = document.querySelector<HTMLElement>(`.site-card[data-site="${site}"]`)!;
    const resetKind = card.querySelector<HTMLSelectElement>('[data-key="resetKind"]')!.value as ResetRuleKind;
    next.sites[site] = {
      ...next.sites[site],
      enabled: card.querySelector<HTMLInputElement>('[data-key="enabled"]')!.checked,
      resetRule: {
        kind: resetKind,
        intervalMinutes: readNumber(card.querySelector<HTMLInputElement>('[data-key="intervalMinutes"]')!.value),
        anchorLocalTime: card.querySelector<HTMLInputElement>('[data-key="anchorLocalTime"]')!.value,
        dayOfWeek: readNumber(card.querySelector<HTMLInputElement>('[data-key="dayOfWeek"]')!.value),
        inferred: true,
        description: next.sites[site].resetRule.description
      },
      tokenBudget: readNumber(card.querySelector<HTMLInputElement>('[data-key="tokenBudget"]')!.value),
      contextWindow: readNumber(card.querySelector<HTMLInputElement>('[data-key="contextWindow"]')!.value),
      quotaTierLabel: card.querySelector<HTMLInputElement>('[data-key="quotaTierLabel"]')!.value,
      costInputPer1k: readNumber(card.querySelector<HTMLInputElement>('[data-key="costInputPer1k"]')!.value),
      costOutputPer1k: readNumber(card.querySelector<HTMLInputElement>('[data-key="costOutputPer1k"]')!.value)
    };
  }

  return next;
}

async function render(): Promise<void> {
  let snapshot = await sendRuntimeMessage<AppSnapshot>({ type: 'get-snapshot' });
  const preferences = snapshot.state.preferences;

  fillSelect(document.querySelector<HTMLSelectElement>('#theme')!, [
    { value: 'system', label: 'System' },
    { value: 'dark', label: 'Dark' },
    { value: 'light', label: 'Light' }
  ], preferences.theme);

  fillSelect(document.querySelector<HTMLSelectElement>('#privacy-mode')!, [
    { value: 'local-only', label: 'Local only' },
    { value: 'sync-preferences', label: 'Sync preferences' }
  ], preferences.privacyMode);

  fillSelect(document.querySelector<HTMLSelectElement>('#badge-mode')!, [
    { value: 'percent', label: 'Percent used' },
    { value: 'remaining', label: 'Remaining tokens' },
    { value: 'off', label: 'Off' }
  ], preferences.alerts.badgeMode);

  document.querySelector<HTMLInputElement>('#show-overlay')!.checked = preferences.showOverlay;
  document.querySelector<HTMLInputElement>('#compact-mode')!.checked = preferences.compactMode;
  document.querySelector<HTMLInputElement>('#desktop-notifications')!.checked = preferences.alerts.desktopNotifications;
  document.querySelector<HTMLInputElement>('#quota-warning-percent')!.value = String(preferences.alerts.quotaWarningPercent);
  document.querySelector<HTMLInputElement>('#large-prompt-tokens')!.value = String(preferences.alerts.largePromptTokens);
  document.querySelector<HTMLInputElement>('#anomaly-multiplier')!.value = String(preferences.alerts.anomalyMultiplier);

  siteSettings.innerHTML = siteOrder.map((site) => renderSiteCard(site, preferences)).join('');

  document.querySelector<HTMLButtonElement>('#save-btn')!.onclick = async () => {
    const payload = collectPreferences(snapshot);
    snapshot = await sendRuntimeMessage<AppSnapshot>({ type: 'save-preferences', payload });
    setStatus('Saved settings. New assumptions will be used on the next session refresh.');
  };

  document.querySelector<HTMLButtonElement>('#test-notification-btn')!.onclick = async () => {
    await sendRuntimeMessage({ type: 'notify', title: 'Yor Token Usage', message: 'Notifications are enabled and working.' });
    setStatus('Test notification sent.');
  };

  document.querySelector<HTMLButtonElement>('#export-btn')!.onclick = async () => {
    const payload = await sendRuntimeMessage({ type: 'export-data' });
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement('a');
    anchor.href = url;
    anchor.download = 'yor-token-usage-export.json';
    anchor.click();
    URL.revokeObjectURL(url);
    setStatus('Exported data to JSON.');
  };

  document.querySelector<HTMLInputElement>('#import-input')!.onchange = async (event) => {
    const file = (event.currentTarget as HTMLInputElement).files?.[0];
    if (!file) return;
    const text = await file.text();
    const parsed = JSON.parse(text);
    snapshot = await sendRuntimeMessage<AppSnapshot>({ type: 'import-data', payload: parsed });
    setStatus('Imported data. Refreshing the settings view.');
    await render();
  };

  document.querySelector<HTMLButtonElement>('#restore-defaults-btn')!.onclick = async () => {
    snapshot = await sendRuntimeMessage<AppSnapshot>({ type: 'save-preferences', payload: DEFAULT_PREFERENCES });
    setStatus('Restored default settings.');
    await render();
  };
}

void render();
